UI=goal::GuiObject lineGUI=line::GuiObject scCheckGUI=check::GuiObject return goal end function Shared.restoreRotationHook()local state=hookState if not state then return end state.active=false state.logic=nil if state.original and hookmetamethod then pcall(function()hookmetamethod(game,"__index",state.original)end)end indexOriginal=nil hookState=nil end function Shared.installRotationHook()if indexOriginal or not(hookmetamethod and newcclosure)then return end if hookState and hookState.original and hookState.logic~=Shared.Logic then pcall(function()hookmetamethod(game,"__index",hookState.original)end)hookState=nil end local isCallerCheck=type(checkcaller)=="function"and checkcaller or function()return false end local state={active=true,logic=nil,original=nil,}local ok,original=pcall(function()return hookmetamethod(game,"__index",newcclosure(function(self,index)if state.active and not isCallerCheck()and Shared.autoSkillcheckEnabled and Shared.skillCheckMode=="RotationHook"and index=="Rotation"then local goal=resolveGoalForLine(self)if goal then local rotation=SKILL_ROTATION.Perfect return rotation+goal.Rotation end end local originalIndex=state.original or indexOriginal if originalIndex then return originalIndex(self,index)end return nil end))end)if ok and type(original)=="function"then indexOriginal=original state.original=original hookState=state else state.active=false end end local function disconnectSkillCheckEvent(event)local connection=skillCheckEventConnections[event]if connection then connection:Disconnect()skillCheckEventConnections[event]=nil end end local function connectSkillCheckEvent(event)if skillCheckEventConnections[event]then return end skillCheckEventConnections[event]=event.OnClientEvent:Connect(function()if not Shared.autoSkillcheckEnabled or Shared.skillCheckMode~="RotationHook"then return end refreshSkillCheckGui()task.delay(0.7,function()if Shared.autoSkillcheckEnabled and Shared.skillCheckMode=="RotationHook"and not Shared.lobbyLocked then 