,16)pct.BackgroundTransparency=1 pct.Font=Enum.Font.GothamBold pct.Text="0%"pct.TextColor3=COL.sub pct.TextSize=isSmall and 10 or 12 pct.Parent=overlay self._pct=pct local cat=self._cat local paws=self._paws local pawSp=pawSpacing local pY=pawY local pawSpeed=55*scale local maxDist=70*scale local conn=RunService.RenderStepped:Connect(function(dt:number)cat.bounce=(cat.bounce+dt*10)%(math.pi*2)local bounceY=math.sin(cat.bounce)*6*cat.scale cat.frame.Position=UDim2.new(0.5,0,0.5,bounceY)cat.tailWag=(cat.tailWag+dt*5)%(math.pi*2)cat.tail.Rotation=math.sin(cat.tailWag)*20 cat.leftEar.Rotation=45+math.sin(cat.bounce*2)*4 cat.rightEar.Rotation=-45-math.sin(cat.bounce*2)*4 cat.blinkTimer=cat.blinkTimer+dt local blinkInterval=3.0 local blinkDuration=0.15 if cat.blinkTimer>blinkInterval then local phase=(cat.blinkTimer-blinkInterval)/blinkDuration if phase<1 then local eyeH=math.max(1,9*cat.scale*math.abs(math.cos(phase*math.pi)))cat.leftEye.Size=UDim2.fromOffset(7*cat.scale,eyeH)cat.rightEye.Size=UDim2.fromOffset(7*cat.scale,eyeH)local hlT=math.abs(math.cos(phase*math.pi))cat.leftHL.BackgroundTransparency=hlT cat.rightHL.BackgroundTransparency=hlT else cat.blinkTimer=0 cat.leftEye.Size=UDim2.fromOffset(7*cat.scale,9*cat.scale)cat.rightEye.Size=UDim2.fromOffset(7*cat.scale,9*cat.scale)cat.leftHL.BackgroundTransparency=0 cat.rightHL.BackgroundTransparency=0 end end for _,paw in ipairs(paws)do paw.offset=paw.offset-pawSpeed*dt if paw.offset<-pawSp then paw.offset=paw.offset+pawSp*4 end paw.frame.Position=UDim2.fromOffset(paw.offset,pY)local dist=math.abs(paw.offset)local trans=0.15+math.min(dist,maxDist)/maxDist*0.85 for _,child in ipairs(paw.children)do child.BackgroundTransparency=trans end end local current=self._currentProgress local target=self._progress if current~=target then local nextProgress=current+(target-current)*(1-0.5^(dt*20))if math.abs(target-nextProgress)<0.001 then nextProgress=target end self._currentProgress=nextProgress fill.Size=UDim2.fromScale(nextProgress,1)local pctVal=math.floor(nextProgress*100+0.5)if self._lastPct~=pctVal then self._lastPct=pctVal pct.Text=tostring(pctVal).."%"end end end)table.insert(self._conns,conn)return self end function Loader:setStatus(text:any)if self._status then self._status.Text=tostring(text)end end function Loader:setProgress(p:number)self._progress=math.clamp(p,0,1)end function Loader:finish(callback:(()->())?)self:setProgress(1)task.delay(0.25,function()if self._overlay then TweenService:Create(self._overlay,TweenInfo.new(0.4),{BackgroundTransparency=1}):Play()for _,ch in ipairs(self._overlay:GetDescendants())do if ch:IsA("TextLabel")then TweenService:Create(ch,TweenInfo.new(0.4),{TextTransparency=1}):Play()elseif ch:IsA("Frame")then TweenService:Create(ch,TweenInfo.new(0.4),{BackgroundTransparency=1}):Play()elseif ch:IsA("UIStroke")then TweenService:Create(ch,TweenInfo.new(0.4),{Transparency=1}):Play()end end end if self._blur then TweenService:Create(self._blur,TweenInfo.new(0.4),{Size=0}):Play()end task.delay(0.45,function()self:destroy()if type(callback)=="function"then local ok,err=pcall(callback::()->())if not ok then warn("[Neko_Hub] loader callback error: "..tostring(err))end end end)end)end function Loader:destroy()for _,c in ipairs(self._conns)do pcall(function()c:Disconnect()end)end self._conns={}if self._gui then pcall(function()self._gui:Destroy()end)end if self._blur then pcall(function()self._blur:Destroy()end)end end if not(getgenv and getgenv().Neko_HubLoaderModule)then task.spawn(function()local L=Loader.new()L:setStatus("Loading Neko_Hub...")local p=0 while p<1 do p=math.min(1,p+math.random(2,6)/100)L:setProgress(p)task.wait(0.06)end L:setStatus("Done!")L:finish(function()end)end)end return Loader end EmbeddedModules["Neko_HubGui/Menu"]=function()local NekoUI=getgenv().NekoUI local Window=getgenv().Window if not NekoUI or not Window then return end local Logic=loadModule("Neko_HubGui/LogicFunction")if type(Logic)~="table"then Logic=getgenv().Neko_HubLogic end