5,Flag="neko_pallet_dist",Callback=function(v)if Combat and Combat.SetPalletDistance then Combat.SetPalletDistance(v)end end,})CombatTab:AddSection({Title="Skillcheck Settings"})CombatTab:AddToggle({Title="Auto Skillcheck",Desc="Automatically hit perfect skillchecks",Default=false,Flag="neko_skillcheck",Callback=function(v)if Combat and Combat.SetAutoSkillcheck then Combat.SetAutoSkillcheck(v)end end,})CombatTab:AddDropdown({Title="Skillcheck Mode",Desc="Crossing: UI perfect (~104) + miss failsafe. RotationHook: __index. RemoteSuccess: remote result success",Values={"Crossing","RotationHook","RemoteSuccess"},Default="Crossing",Flag="neko_skillcheck_mode",Callback=function(v)if Combat and Combat.SetSkillCheckMode then Combat.SetSkillCheckMode(v)end end,})CombatTab:AddSection({Title="Vault Settings"})CombatTab:AddToggle({Title="Fast Vault",Desc="Always vault at sprint speed regardless of sprinting state",Default=false,Flag="neko_vault",Callback=function(v)if Combat and Combat.SetFastVault then Combat.SetFastVault(v)end end,})AntiTab:AddSection({Title="Anti Settings"})AntiTab:AddToggle({Title="Anti Auto Parry",Desc="Bait survivors' auto parry by playing a silent swing animation",Default=false,Flag="neko_anti_parry",Callback=function(v)if Combat and Combat.SetAntiAutoParry then Combat.SetAntiAutoParry(v)end end,})VisualTab:AddSection({Title="ESP Settings"})VisualTab:AddToggle({Title="ESP",Desc="Enable ESP visuals",Default=false,Flag="neko_esp",Callback=function(v)if ESP and ESP.SetMasterEnabled then ESP.SetMasterEnabled(v)end end,})VisualTab:AddDropdown({Title="Select Esp",Desc="Choose which ESP elements to display",Values={"Killer","Survivor","Generator","Pallet","Window","Hook","Zombie"},Default={},Multi=true,Flag="neko_esp_select",Callback=function(v)if ESP and ESP.SetSelectedKinds then ESP.SetSelectedKinds(v)end end,})VisualTab:AddDropdown({Title="Highlight Style",Desc="Fill = tinted body; Outline = edge only",Values={"Outline","Fill"},Default="Outline",Flag="neko_e