le="Zombie Color",Default=Color3.fromRGB(255,60,60),Flag="neko_color_zombie",Callback=function(c)if ESP and ESP.SetColor then ESP.SetColor("SCP",c)end end,})VisualTab:AddColorPicker({Title="Killer Color",Default=Color3.fromRGB(255,60,60),Flag="neko_color_killer",Callback=function(c)if ESP and ESP.SetColor then ESP.SetColor("Killer",c)end end,})VisualTab:AddColorPicker({Title="Survivor Color",Default=Color3.fromRGB(0,255,170),Flag="neko_color_survivor",Callback=function(c)if ESP and ESP.SetColor then ESP.SetColor("Survivor",c)end end,})VisualTab:AddColorPicker({Title="Downed Player Color",Default=Color3.fromRGB(255,0,0),Flag="neko_color_downed",Callback=function(c)if ESP and ESP.SetColor then ESP.SetColor("PlayerDowned",c)end end,})AimTab:AddSection({Title="Aim Gun Settings"})AimTab:AddDropdown({Title="Aim Gun",Desc="Select Aim Gun mode",Values={"Disabled","Silent Aim","Aim Lock","Both"},Default="Both",Flag="neko_aimgun",Callback=function(value)if Aim then setAimMode(Aim.SetSilentAim,Aim.SetAimLock,value)end end,})AimTab:AddDropdown({Title="Aim Target",Desc="Target team selection",Values={"Killer","Survivor"},Default="Killer",Flag="neko_aim_target",Callback=function(v)if Aim and Aim.SetTargetMode then Aim.SetTargetMode(v)end end,})AimTab:AddToggle({Title="Show FOV",Desc="Show FOV circle",Default=false,Flag="neko_aim_showfov",Callback=function(v)if Aim and Aim.SetShowFov then Aim.SetShowFov(v)end end,})AimTab:AddSlider({Title="FOV Radius",Range={30,300},Increment=1,Default=120,Flag="neko_aim_fov",Callback=function(v)if Aim and Aim.SetFovRadius then Aim.SetFovRadius(v)end end,})AimTab:AddToggle({Title="Wallcheck",Desc="Aim only at visible targets",Default=true,Flag="neko_aim_wallcheck",Callback=function(v)if Aim and Aim.SetWallcheck then Aim.SetWallcheck(v)end end,})AimTab:AddToggle({Title="Predict Movement",Desc="Predict target movement trajectory",Default=true,Flag="neko_aim_predict",Callback=function(v)if Aim and Aim.SetEnableLead then Aim.SetEnableLead(v)end end,})AimTab:AddSlider({Title="Aim Smooth",Range={0.05,1.0},Increment=0.05,Default=0.25,Flag="neko_aim_smooth",Callback=function(v)if Aim and Aim.SetSmooth then Aim.SetSmooth(v)end end,})AimTab:AddSection({Title="Aim Veil Settings"})AimTab:AddDropdown({Title="Aim Veil",Desc="Select Aim Veil mode",Values={"Disabled","Silent Aim","Aim Lock","Both"},Default="Both",Flag="neko_aimveil",Callback=function(value)if Aim then setAimMode(Aim.SetVeilSilentAim,Aim.SetVeilAimLock,value)end end,})AimTab:AddToggle({Title="Show FOV (Veil)",Desc="Show FOV circle for Veil",Default=false,Flag="neko_aimveil_showfov",Callback=function(v)if Aim and Aim.SetVeilShowFov then Aim.SetVeilShowFov(v)end end,})AimTab:AddSlider({Title="FOV Radius (Veil)",Range={50,400},Increment=1,Default=150,Flag="neko_aimveil_fov",Callback=function(v)if Aim and Aim.SetVeilFovRadius then Aim.SetVeilFovRadius(v)end end,})AimTab:AddToggle({Title="Predict Movement (Veil)",Desc="Predict target movement trajectory for Veil",Default=true,Flag="neko_aimveil_predict",Callback=function(v)if Aim and Aim.SetVeilEnableLead then Aim.SetVeilEnableLead(v)end end,})AimTab:AddToggle({Title="Show Power HUD (Veil)",Desc="Mini side bar for spear charge power (spearmode)",Default=true,Flag="neko_aimveil_showpower",Callback=function(v)if Aim and Aim.SetVeilShowPower then Aim.SetVeilShowPower(v)end end,})local function setAimMode(setSilent,setLock,value)if value=="Disabled"then setSilent(false);setLock(false)elseif value=="Silent Aim"then setSilent(true);setLock(false)elseif value=="Aim Lock"then setSilent(false);setLock(true)elseif value=="Both"then setSilent(true);setLock(true)end end PlayerTab:AddSection({Title="Camera Settings"})PlayerTab:AddToggle({Title="Unlimited Zoom",Desc="Unlock camera zoom distance",Default=false,Flag="neko_player_zoom",Callback=function(v)if Player and Player.SetUnlimitedZoom then Player.SetUnlimitedZoom(v)end end,})PlayerTab:AddSlider({Title="Max Zoom Distance",Range={100,5000},Increment=1,Default=1000,Flag="neko_player_zoomdist",Callback=function(v)if Player and Player.SetMaxZoomDistance then Player.SetMaxZoomDistance(v)end end,})PlayerTab:AddToggle({Title="Custom FOV",Desc="Override default field of view",Default=false,Flag="neko_player_fov",Callback=function(v)if Player and Player.SetCustomFOV then Player.SetCustomFOV(v)end end,})PlayerTab:AddSlider({Title="Camera FOV",Range={40,120},Increment=1,Default=70,Flag="neko_player_fovval",Callback=function(v)if Player and Player.SetFOV then Player.SetFOV(v)end end,})PlayerTab:AddSection({Title="Lighting"})PlayerTab:AddToggle({Title="Fullbright",Desc="Brighten the map (removes fog/shadows)",Default=false,Flag="neko_fullbright",Callback=function(v)if Player and Player.SetFullbright then Player.SetFullbright(v)end end,})PlayerTab:AddSection({Title="Player Info"})local selectedInfoPlayer:string?=nil local playerInfoDropdown:any local function getInfoPlayerOptions():{string}if Player and Player.GetPlayerNames then return Player.GetPlayerNames()end return{"(none)"}end playerInfoDropdown=PlayerTab:AddDropdown({Title="Select Player",Desc="Choose a player to inspect",Values=getInfoPlayerOptions(),Default=getInfoPlayerOptions()[1],Flag="neko_info_player",Callback=function(v)selectedInfoPlayer=v end,})local function refreshInfoPlayerDropdown()local names=getInfoPlayerOptions()if selectedInfoPlayer==nil or not table.find(names,selectedInfoPlayer)then selectedInfoPlayer=names[1]end if playerInfoDropdown and type(playerInfoDropdown.Refresh)=="function"then pcall(function()playerInfoDropdown:Refresh(names,true)end)end end PlayerTab:AddButton({Title="Refresh Player List",Callback=function()refreshInfoPlayerDropdown()end,})PlayerTab:AddButton({Title="Show Info",Callback=function()if Player and Player.ShowPlayerInfo then Player.ShowPlayerInfo(selectedInfoPlayer)end end,})pcall(function()local PlayersSvc=game:GetService("Players")PlayersSvc.PlayerAdded:Connect(function()task.defer(refreshInfoPlayerDropdown)end)PlayersSvc.PlayerRemoving:Connect(f